mapper.select:
select count(1)
from flight_dish fd
         inner join flight_info fi on fi.id = fd.flight_id
where fi.flight_number = #{flightNumber}
  and fd.dish_id = #{dishId}
  and fd.cabin_type = #{cabinType}

      and fd.id != #{excludeId}

mapper.update:
update flight_dish
set flight_id = #{flightId},
    dish_id = #{dishId},
    cabin_type = #{cabinType},
    sort = #{sort}
where id = #{id}
